from __future__ import annotations

from dataclasses import asdict, dataclass, field, is_dataclass
import hashlib
import json
from typing import Any, Dict, List, Mapping, Optional

from src.trader.execution.allocation_decision import (
    AllocationDecision,
    AllocationDecisionError,
)


class AllocationReviewPacketBuilderError(RuntimeError):
    """Raised when allocation review packet inputs are invalid."""


def _require_non_empty_string(name: str, value: Any) -> str:
    if not isinstance(value, str) or not value.strip():
        raise AllocationReviewPacketBuilderError(f"{name} must be a non-empty string")
    return value.strip()


def _normalize_non_negative_int(name: str, value: Any) -> int:
    if isinstance(value, bool) or not isinstance(value, int):
        raise AllocationReviewPacketBuilderError(f"{name} must be a non-negative integer")
    if value < 0:
        raise AllocationReviewPacketBuilderError(f"{name} must be a non-negative integer")
    return value


def _normalize_non_negative_float(name: str, value: Any) -> float:
    if isinstance(value, bool):
        raise AllocationReviewPacketBuilderError(f"{name} must be a non-negative number")
    if isinstance(value, str):
        try:
            value = float(value.strip())
        except ValueError as exc:
            raise AllocationReviewPacketBuilderError(f"{name} must be a non-negative number") from exc
    if not isinstance(value, (int, float)):
        raise AllocationReviewPacketBuilderError(f"{name} must be a non-negative number")
    normalized = float(value)
    if normalized < 0.0:
        raise AllocationReviewPacketBuilderError(f"{name} must be a non-negative number")
    return normalized


def _normalize_string_list(name: str, value: Any) -> List[str]:
    if value is None:
        return []
    if not isinstance(value, list):
        raise AllocationReviewPacketBuilderError(f"{name} must be a list when provided")
    normalized: List[str] = []
    for item in value:
        normalized.append(_require_non_empty_string(f"{name}[]", item))
    return normalized


def _normalize_metadata(value: Any) -> Dict[str, Any]:
    if value is None:
        return {}
    if not isinstance(value, Mapping):
        raise AllocationReviewPacketBuilderError("metadata must be a mapping when provided")
    return dict(value)


def _mapping_from_value(name: str, value: Any) -> Dict[str, Any]:
    if value is None:
        raise AllocationReviewPacketBuilderError(f"{name} is required")
    if isinstance(value, Mapping):
        return dict(value)

    to_dict = getattr(value, "to_dict", None)
    if callable(to_dict):
        payload = to_dict()
        if not isinstance(payload, Mapping):
            raise AllocationReviewPacketBuilderError(f"{name}.to_dict() must return a mapping")
        return dict(payload)

    if is_dataclass(value) and not isinstance(value, type):
        payload = asdict(value)
        if not isinstance(payload, dict):
            raise AllocationReviewPacketBuilderError(f"{name} dataclass did not normalize to a dict")
        return payload

    if hasattr(value, "__dict__"):
        return {key: item for key, item in vars(value).items() if not key.startswith("_")}

    raise AllocationReviewPacketBuilderError(f"{name} must be mapping-like or expose to_dict()")


def _stable_id(prefix: str, payload: Mapping[str, Any]) -> str:
    digest = hashlib.sha256(
        json.dumps(dict(payload), sort_keys=True, default=str).encode("utf-8")
    ).hexdigest()[:16]
    return f"{prefix}_{digest}"


def _normalize_allocation_decision(value: Any) -> AllocationDecision:
    if isinstance(value, AllocationDecision):
        return value

    if hasattr(AllocationDecision, "from_dict"):
        try:
            return AllocationDecision.from_dict(_mapping_from_value("allocation_decision", value))
        except (TypeError, ValueError, AllocationDecisionError) as exc:
            raise AllocationReviewPacketBuilderError(
                "allocation_decision could not be normalized"
            ) from exc

    raise AllocationReviewPacketBuilderError("AllocationDecision.from_dict is not available")


@dataclass(frozen=True)
class AllocationReviewPacketItem:
    allocation_candidate_id: str
    decision_status: str
    chain: str
    strategy_id: str
    symbol: str
    pair: str
    side: str
    proposed_exposure_usd: float
    reserved_capital_usd: float
    approval_reasons: List[str] = field(default_factory=list)
    block_reasons: List[str] = field(default_factory=list)
    explanation_lines: List[str] = field(default_factory=list)
    chain_strategy_budget_policy_id: Optional[str] = None
    budget_candidate_key: Optional[str] = None
    metadata: Dict[str, Any] = field(default_factory=dict)
    allocation_review_packet_item_id: str = field(init=False)

    def __post_init__(self) -> None:
        allocation_candidate_id = _require_non_empty_string(
            "allocation_candidate_id",
            self.allocation_candidate_id,
        )
        decision_status = _require_non_empty_string("decision_status", self.decision_status).upper()
        if decision_status not in {"APPROVED", "BLOCKED"}:
            raise AllocationReviewPacketBuilderError("decision_status must be APPROVED or BLOCKED")

        chain = _require_non_empty_string("chain", self.chain).lower()
        strategy_id = _require_non_empty_string("strategy_id", self.strategy_id).lower()
        symbol = _require_non_empty_string("symbol", self.symbol).upper()
        pair = _require_non_empty_string("pair", self.pair).upper()
        side = _require_non_empty_string("side", self.side).upper()
        proposed_exposure_usd = _normalize_non_negative_float(
            "proposed_exposure_usd",
            self.proposed_exposure_usd,
        )
        reserved_capital_usd = _normalize_non_negative_float(
            "reserved_capital_usd",
            self.reserved_capital_usd,
        )
        approval_reasons = _normalize_string_list("approval_reasons", self.approval_reasons)
        block_reasons = _normalize_string_list("block_reasons", self.block_reasons)
        explanation_lines = _normalize_string_list("explanation_lines", self.explanation_lines)
        chain_strategy_budget_policy_id = (
            None if self.chain_strategy_budget_policy_id is None
            else _require_non_empty_string(
                "chain_strategy_budget_policy_id",
                self.chain_strategy_budget_policy_id,
            )
        )
        budget_candidate_key = (
            None if self.budget_candidate_key is None
            else _require_non_empty_string("budget_candidate_key", self.budget_candidate_key)
        )
        metadata = _normalize_metadata(self.metadata)

        if decision_status == "APPROVED":
            if reserved_capital_usd <= 0.0:
                raise AllocationReviewPacketBuilderError(
                    "approved review items must reserve positive capital"
                )
            if block_reasons:
                raise AllocationReviewPacketBuilderError(
                    "approved review items must not include block_reasons"
                )
            if not explanation_lines:
                explanation_lines = [
                    f"Approved for {symbol} on {chain} via strategy {strategy_id}.",
                    *[f"Reason: {reason}" for reason in approval_reasons],
                ]
        else:
            if reserved_capital_usd != 0.0:
                raise AllocationReviewPacketBuilderError(
                    "blocked review items must reserve zero capital"
                )
            if not block_reasons:
                raise AllocationReviewPacketBuilderError(
                    "blocked review items must include block_reasons"
                )
            if not explanation_lines:
                explanation_lines = [
                    f"Blocked for {symbol} on {chain} via strategy {strategy_id}.",
                    *[f"Block: {reason}" for reason in block_reasons],
                ]

        object.__setattr__(self, "allocation_candidate_id", allocation_candidate_id)
        object.__setattr__(self, "decision_status", decision_status)
        object.__setattr__(self, "chain", chain)
        object.__setattr__(self, "strategy_id", strategy_id)
        object.__setattr__(self, "symbol", symbol)
        object.__setattr__(self, "pair", pair)
        object.__setattr__(self, "side", side)
        object.__setattr__(self, "proposed_exposure_usd", proposed_exposure_usd)
        object.__setattr__(self, "reserved_capital_usd", reserved_capital_usd)
        object.__setattr__(self, "approval_reasons", approval_reasons)
        object.__setattr__(self, "block_reasons", block_reasons)
        object.__setattr__(self, "explanation_lines", explanation_lines)
        object.__setattr__(self, "chain_strategy_budget_policy_id", chain_strategy_budget_policy_id)
        object.__setattr__(self, "budget_candidate_key", budget_candidate_key)
        object.__setattr__(self, "metadata", metadata)
        object.__setattr__(
            self,
            "allocation_review_packet_item_id",
            _stable_id(
                "allocation_review_packet_item",
                {
                    "allocation_candidate_id": allocation_candidate_id,
                    "decision_status": decision_status,
                    "chain": chain,
                    "strategy_id": strategy_id,
                    "symbol": symbol,
                    "pair": pair,
                    "side": side,
                    "reserved_capital_usd": reserved_capital_usd,
                },
            ),
        )

    def to_dict(self) -> Dict[str, Any]:
        return {
            "allocation_candidate_id": self.allocation_candidate_id,
            "decision_status": self.decision_status,
            "chain": self.chain,
            "strategy_id": self.strategy_id,
            "symbol": self.symbol,
            "pair": self.pair,
            "side": self.side,
            "proposed_exposure_usd": self.proposed_exposure_usd,
            "reserved_capital_usd": self.reserved_capital_usd,
            "approval_reasons": list(self.approval_reasons),
            "block_reasons": list(self.block_reasons),
            "explanation_lines": list(self.explanation_lines),
            "chain_strategy_budget_policy_id": self.chain_strategy_budget_policy_id,
            "budget_candidate_key": self.budget_candidate_key,
            "metadata": dict(self.metadata),
            "allocation_review_packet_item_id": self.allocation_review_packet_item_id,
        }

    @classmethod
    def from_dict(cls, payload: Mapping[str, Any]) -> "AllocationReviewPacketItem":
        if not isinstance(payload, Mapping):
            raise AllocationReviewPacketBuilderError("payload must be a mapping")
        return cls(
            allocation_candidate_id=payload.get("allocation_candidate_id"),
            decision_status=payload.get("decision_status"),
            chain=payload.get("chain"),
            strategy_id=payload.get("strategy_id"),
            symbol=payload.get("symbol"),
            pair=payload.get("pair"),
            side=payload.get("side"),
            proposed_exposure_usd=payload.get("proposed_exposure_usd"),
            reserved_capital_usd=payload.get("reserved_capital_usd"),
            approval_reasons=list(payload.get("approval_reasons") or []),
            block_reasons=list(payload.get("block_reasons") or []),
            explanation_lines=list(payload.get("explanation_lines") or []),
            chain_strategy_budget_policy_id=payload.get("chain_strategy_budget_policy_id"),
            budget_candidate_key=payload.get("budget_candidate_key"),
            metadata=dict(payload.get("metadata") or {}),
        )


@dataclass(frozen=True)
class AllocationReviewPacket:
    allocator_cycle_id: str
    allocation_decision_id: str
    approved_count: int
    blocked_count: int
    total_reserved_capital_usd: float
    items: List[AllocationReviewPacketItem] = field(default_factory=list)
    summary_lines: List[str] = field(default_factory=list)
    metadata: Dict[str, Any] = field(default_factory=dict)
    allocation_review_packet_id: str = field(init=False)

    def __post_init__(self) -> None:
        allocator_cycle_id = _require_non_empty_string("allocator_cycle_id", self.allocator_cycle_id)
        allocation_decision_id = _require_non_empty_string(
            "allocation_decision_id",
            self.allocation_decision_id,
        )
        approved_count = _normalize_non_negative_int("approved_count", self.approved_count)
        blocked_count = _normalize_non_negative_int("blocked_count", self.blocked_count)
        total_reserved_capital_usd = _normalize_non_negative_float(
            "total_reserved_capital_usd",
            self.total_reserved_capital_usd,
        )
        items = [
            item if isinstance(item, AllocationReviewPacketItem)
            else AllocationReviewPacketItem.from_dict(_mapping_from_value("item", item))
            for item in self.items
        ]
        summary_lines = _normalize_string_list("summary_lines", self.summary_lines)
        metadata = _normalize_metadata(self.metadata)

        derived_approved_count = sum(1 for item in items if item.decision_status == "APPROVED")
        derived_blocked_count = sum(1 for item in items if item.decision_status == "BLOCKED")
        derived_reserved_capital = sum(item.reserved_capital_usd for item in items)

        if approved_count != derived_approved_count:
            raise AllocationReviewPacketBuilderError("approved_count does not match review items")
        if blocked_count != derived_blocked_count:
            raise AllocationReviewPacketBuilderError("blocked_count does not match review items")
        if round(total_reserved_capital_usd, 8) != round(derived_reserved_capital, 8):
            raise AllocationReviewPacketBuilderError(
                "total_reserved_capital_usd does not match review items"
            )

        if not summary_lines:
            summary_lines = [
                f"Allocator cycle {allocator_cycle_id} reviewed {len(items)} candidates.",
                f"Approved: {approved_count}.",
                f"Blocked: {blocked_count}.",
                f"Reserved capital: {total_reserved_capital_usd:.2f} USD.",
            ]

        object.__setattr__(self, "allocator_cycle_id", allocator_cycle_id)
        object.__setattr__(self, "allocation_decision_id", allocation_decision_id)
        object.__setattr__(self, "approved_count", approved_count)
        object.__setattr__(self, "blocked_count", blocked_count)
        object.__setattr__(self, "total_reserved_capital_usd", total_reserved_capital_usd)
        object.__setattr__(self, "items", items)
        object.__setattr__(self, "summary_lines", summary_lines)
        object.__setattr__(self, "metadata", metadata)
        object.__setattr__(
            self,
            "allocation_review_packet_id",
            _stable_id(
                "allocation_review_packet",
                {
                    "allocator_cycle_id": allocator_cycle_id,
                    "allocation_decision_id": allocation_decision_id,
                    "approved_count": approved_count,
                    "blocked_count": blocked_count,
                    "total_reserved_capital_usd": total_reserved_capital_usd,
                    "item_ids": [item.allocation_review_packet_item_id for item in items],
                },
            ),
        )

    def to_dict(self) -> Dict[str, Any]:
        return {
            "allocator_cycle_id": self.allocator_cycle_id,
            "allocation_decision_id": self.allocation_decision_id,
            "approved_count": self.approved_count,
            "blocked_count": self.blocked_count,
            "total_reserved_capital_usd": self.total_reserved_capital_usd,
            "items": [item.to_dict() for item in self.items],
            "summary_lines": list(self.summary_lines),
            "metadata": dict(self.metadata),
            "allocation_review_packet_id": self.allocation_review_packet_id,
        }

    @classmethod
    def from_dict(cls, payload: Mapping[str, Any]) -> "AllocationReviewPacket":
        if not isinstance(payload, Mapping):
            raise AllocationReviewPacketBuilderError("payload must be a mapping")
        return cls(
            allocator_cycle_id=payload.get("allocator_cycle_id"),
            allocation_decision_id=payload.get("allocation_decision_id"),
            approved_count=payload.get("approved_count"),
            blocked_count=payload.get("blocked_count"),
            total_reserved_capital_usd=payload.get("total_reserved_capital_usd"),
            items=list(payload.get("items") or []),
            summary_lines=list(payload.get("summary_lines") or []),
            metadata=dict(payload.get("metadata") or {}),
        )


def normalize_allocation_review_packet(value: Any) -> AllocationReviewPacket:
    if isinstance(value, AllocationReviewPacket):
        return value
    return AllocationReviewPacket.from_dict(_mapping_from_value("allocation_review_packet", value))


def _candidate_field(candidate_payload: Mapping[str, Any], name: str) -> Any:
    value = candidate_payload.get(name)
    if value is None:
        raise AllocationReviewPacketBuilderError(f"candidate field {name} is required")
    return value


def _extract_review_item_payloads(decision: AllocationDecision) -> List[Dict[str, Any]]:
    payloads: List[Dict[str, Any]] = []
    decision_payload = decision.to_dict()

    approved_items = list(decision_payload.get("approved_items") or [])
    blocked_items = list(decision_payload.get("blocked_items") or [])

    for raw_item in approved_items + blocked_items:
        if not isinstance(raw_item, Mapping):
            raise AllocationReviewPacketBuilderError("decision items must be mappings")
        item = dict(raw_item)
        candidate_payload = dict(item.get("candidate") or {})

        payloads.append(
            {
                "allocation_candidate_id": item.get("allocation_candidate_id")
                or candidate_payload.get("allocation_candidate_id"),
                "decision_status": item.get("decision_status"),
                "chain": item.get("chain") or _candidate_field(candidate_payload, "chain"),
                "strategy_id": item.get("strategy_id") or _candidate_field(candidate_payload, "strategy_id"),
                "symbol": item.get("symbol") or _candidate_field(candidate_payload, "symbol"),
                "pair": item.get("pair") or _candidate_field(candidate_payload, "pair"),
                "side": item.get("side") or _candidate_field(candidate_payload, "side"),
                "proposed_exposure_usd": item.get("proposed_exposure_usd")
                if item.get("proposed_exposure_usd") is not None
                else _candidate_field(candidate_payload, "proposed_exposure_usd"),
                "reserved_capital_usd": item.get("reserved_capital_usd", 0.0),
                "approval_reasons": list(item.get("approval_reasons") or []),
                "block_reasons": list(item.get("block_reasons") or []),
                "chain_strategy_budget_policy_id": item.get("chain_strategy_budget_policy_id"),
                "budget_candidate_key": item.get("budget_candidate_key"),
                "metadata": dict(item.get("metadata") or {}),
            }
        )
    return payloads


def build_allocation_review_packet(
    *,
    allocation_decision: Any,
    metadata: Optional[Mapping[str, Any]] = None,
) -> AllocationReviewPacket:
    decision = _normalize_allocation_decision(allocation_decision)
    payloads = _extract_review_item_payloads(decision)
    items = [AllocationReviewPacketItem.from_dict(payload) for payload in payloads]
    decision_payload = decision.to_dict()

    return AllocationReviewPacket(
        allocator_cycle_id=decision_payload.get("allocator_cycle_id"),
        allocation_decision_id=decision_payload.get("allocation_decision_id"),
        approved_count=sum(1 for item in items if item.decision_status == "APPROVED"),
        blocked_count=sum(1 for item in items if item.decision_status == "BLOCKED"),
        total_reserved_capital_usd=sum(item.reserved_capital_usd for item in items),
        items=items,
        metadata=dict(metadata or {}),
    )


def render_allocation_review_packet_text(packet: Any) -> str:
    normalized_packet = normalize_allocation_review_packet(packet)
    lines: List[str] = [
        "ALLOCATION REVIEW PACKET",
        "------------------------",
        f"Allocator Cycle : {normalized_packet.allocator_cycle_id}",
        f"Decision ID     : {normalized_packet.allocation_decision_id}",
        f"Approved        : {normalized_packet.approved_count}",
        f"Blocked         : {normalized_packet.blocked_count}",
        f"Reserved Capital: {normalized_packet.total_reserved_capital_usd:.2f} USD",
        "",
        "SUMMARY",
        "-------",
    ]
    lines.extend(normalized_packet.summary_lines)

    for index, item in enumerate(normalized_packet.items, start=1):
        lines.extend(
            [
                "",
                f"ITEM {index}",
                "------",
                f"Candidate ID : {item.allocation_candidate_id}",
                f"Status       : {item.decision_status}",
                f"Market       : {item.chain} / {item.strategy_id} / {item.symbol} / {item.side}",
                f"Exposure USD : {item.proposed_exposure_usd:.2f}",
                f"Reserved USD : {item.reserved_capital_usd:.2f}",
            ]
        )
        if item.chain_strategy_budget_policy_id:
            lines.append(f"Policy ID    : {item.chain_strategy_budget_policy_id}")
        if item.budget_candidate_key:
            lines.append(f"Budget Key   : {item.budget_candidate_key}")

        lines.append("Explanation  :")
        lines.extend(f"  - {line}" for line in item.explanation_lines)

    return "\n".join(lines) + "\n"
